    authn_request.set("AssertionConsumerServiceURL", assertion_consumer_service_url)
    authn_request.set("ProtocolBinding", protocol_binding)

    if force_authn:
        authn_request.set("ForceAuthn", "true")
    if is_passive:
        authn_request.set("IsPassive", "true")

    # Add Issuer element
    issuer_elem = etree.SubElement(
        authn_request,
        etree.QName(SAML_ASSERTION_NS, "Issuer"),
    )
